namespace sv_da30b873776b4d5bb0e72cb008eb7bfa.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Circuit-scoped service that holds theme state and notifies subscribers on change.
/// Registered as Scoped so each SignalR circuit (user) gets its own instance.
/// </summary>
public sealed class ThemeService
{
    public Theme CurrentTheme { get; private set; } = Theme.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        if (CurrentTheme == theme) return;
        CurrentTheme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    public void SetAll(Theme theme, string accentColor)
    {
        var changed = CurrentTheme != theme || AccentColor != accentColor;
        CurrentTheme = theme;
        AccentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" title="Current theme">
    @GetIcon() <span style="color: @ThemeService.AccentColor;">@ThemeService.CurrentTheme</span>
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.CurrentTheme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Toggle theme">
    @GetIcon()
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        var next = ThemeService.CurrentTheme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        ThemeService.SetTheme(next);
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.CurrentTheme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var theme in Enum.GetValues<Theme>())
            {
                <button class="btn @(ThemeService.CurrentTheme == theme ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.SetTheme(theme)">
                    @theme
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
        </div>

        <div class="alert alert-info mt-3">
            Current: <strong>@ThemeService.CurrentTheme</strong> theme
            with accent <span style="color: @ThemeService.AccentColor;">■</span>
            <code>@ThemeService.AccentColor</code>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

